MAGIC = b"GSTS"
QUERY_STATUS = 1
RESPONSE_STATUS = 2

MAX_UDP_PAYLOAD = 1400
FRAGMENT_TYPE = 1
FRAG_HEADER_FMT = "!4sBHHH"
FRAG_HEADER_SIZE = struct.calcsize(FRAG_HEADER_FMT)

STATUS_HEADER_FMT = "!4sBIIHH"
STATUS_HEADER_SIZE = struct.calcsize(STATUS_HEADER_FMT)


